let makeCopyIndex = 0;
const makeCopy = (languageOrValue: PlannerLanguage | any, optionalValue?: any) => {
  const language = (typeof languageOrValue === 'string' ? languageOrValue : languages[makeCopyIndex]) as PlannerLanguage;
  const value = optionalValue ?? languageOrValue;
  makeCopyIndex += 1;
  const premium = premiumByLanguage[language];
  const transportOnly = (text: string) => String(text).split('·')[0].trim();
  const transportModes = {
    tram: transportOnly(value.routeTransport.city),
    mixed: transportOnly(value.routeTransport.district),
    car: value.options.car,
    tripCar: value.options.car,
    tripOrganised: value.routeTransport.trip,
    natureMixed: premium.natureTransport,
  };
  return {
    ...value,
    kicker:plannerKickerByLanguage[language],
    scenarios: value.scenarioText.map((entry: string[], index: number) => ({ ...scenarioSettings[index], title:entry[0], copy:entry[1] })),
    interestsList: value.interestsList,
    tripList: value.tripList,
    dashboard: getStayPlannerDashboardCopy(language),
    premium: {
      ...premium,
      distances:['≈ 5 km','≈ 6 km','—','≈ 25 km','0–5 km'],
      groupTips:value.groupNotes,
      familyNotes:value.routes.map(() => value.groupNotes.family),
      transportTips:{tram:value.routeTransport.city,mixed:value.routeTransport.district,car:value.options.car},
      transportModes,
      upsellCurrentBenefits:value.routes.map((_: any, index: number) => value.routes.slice(0,index + 1).map((route: any) => route.title).join(' · ')),
      upsellNextBenefits:value.routes.map((_: any, index: number) => [value.routes[Math.min(index + 1, 4)].title,premium.weatherBuffer,premium.calmEvening]),
    },
  };
};

